const profileRows = $('Read Profile').all().map(i => i.json);
const profile = profileRows.find(r => r.chat_id) || null;
if (!profile) return [];

const chat_id = profile.chat_id;
const targetKcal = Number(profile.target_kcal) || 0;
const targetProtein = Number(profile.target_protein_g) || 0;
const targetFat = Number(profile.target_fat_g) || 0;
const targetCarbs = Number(profile.target_carbs_g) || 0;
const interval = Number(profile.training_days_interval) || 1;

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

const foodToday = $('Read Food Log').all().map(i => i.json).filter(r => String(r.date) === today);
const workoutsToday = $('Read Workout Log').all().map(i => i.json).filter(r => String(r.date) === today);
const walkToday = $('Read Walking Log').all().map(i => i.json).filter(r => String(r.date) === today);

const foodSum = foodToday.reduce((a, r) => ({
  kcal: a.kcal + (Number(r.kcal) || 0),
  protein: a.protein + (Number(r.protein) || 0),
  fat: a.fat + (Number(r.fat) || 0),
  carbs: a.carbs + (Number(r.carbs) || 0),
}), { kcal: 0, protein: 0, fat: 0, carbs: 0 });
foodSum.kcal = Math.round(foodSum.kcal);
foodSum.protein = Math.round(foodSum.protein);
foodSum.fat = Math.round(foodSum.fat);
foodSum.carbs = Math.round(foodSum.carbs);

const walkMin = walkToday.reduce((s, r) => s + (Number(r.duration_min) || 0), 0);
const walkKcal = walkToday.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);
const workoutKcal = workoutsToday.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);

const lines = [];
lines.push('🌙 *Итог дня.*');
lines.push('');

if (foodToday.length === 0) {
  lines.push('Food_log пуст. Либо ничего не ел весь день (что плохо), либо забил на запись (что хуже). Завтра подтянись.');
} else {
  const diffK = foodSum.kcal - targetKcal;
  const diffP = foodSum.protein - targetProtein;
  lines.push(`Калории: ${foodSum.kcal} / ${targetKcal} ккал ${diffK > 200 ? '— перебор на ' + diffK : diffK < -300 ? '— недобор ' + (-diffK) : '— в норме'}.`);
  lines.push(`Белок: ${foodSum.protein} / ${targetProtein} г ${diffP < -15 ? '— ДОБЕРИ перед сном ' + (-diffP) + 'г (творог/казеин/яйца)' : diffP >= 0 ? '✅' : '— почти'}.`);
  lines.push(`Жиры: ${foodSum.fat} / ${targetFat}г · Углеводы: ${foodSum.carbs} / ${targetCarbs}г.`);
}

if (workoutsToday.length) lines.push(`💪 Тренировка: ${workoutsToday[0].day_plan || 'сделана'} — ${Math.round(workoutKcal)} ккал.`);
if (walkMin) lines.push(`🚶 Ходьба: ${walkMin} мин, ${Math.round(walkKcal)} ккал.`);

lines.push('');
// Капральские итоги по результатам
if (foodToday.length > 0) {
  const kIn = foodSum.kcal >= targetKcal - 200 && foodSum.kcal <= targetKcal + 200;
  const pOk = foodSum.protein >= targetProtein * 0.9;
  const wOk = workoutsToday.length > 0 || walkMin >= 30;
  if (kIn && pOk && wOk) lines.push('Сегодня в плюс. Закрепляй привычку, не расслабляйся.');
  else if (!pOk) lines.push('Белка снова мало. До сна — творог/казеин/2 яйца. Это не предложение.');
  else if (!kIn) lines.push(foodSum.kcal > targetKcal ? 'Перебор. Завтра минус 200 ккал — компенсируешь.' : 'Недобор калорий. На дефиците это не геройство, это путь к срыву.');
  else if (!wOk) lines.push('Сегодня двигался мало. Не геройствуй завтра — просто не пропускай.');
}

const text = lines.join('\n');
return [{ json: { chat_id, text } }];
